import React, { useState, useRef, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { Button } from '../design-system/Button/Button';
import { Card } from '../design-system/Card/Card';
import { Badge, Tabs } from '../design-system/Badge/Badge';
import '../theme/variables.css';

const AI = 'http://localhost:8000';

function LiveScribe() {
  const [recording, setRecording] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [result, setResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [tab, setTab] = useState('soap');
  const [edited, setEdited] = useState<any>({});
  const [step, setStep] = useState<'record'|'transcribing'|'generating'|'done'>('record');
  const mediaRecorder = useRef<MediaRecorder | null>(null);
  const chunks = useRef<Blob[]>([]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorder.current = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      chunks.current = [];
      mediaRecorder.current.ondataavailable = e => { if (e.data.size > 0) chunks.current.push(e.data); };
      mediaRecorder.current.onstop = handleTranscribe;
      mediaRecorder.current.start();
      setRecording(true);
      setError(null);
    } catch (e: any) {
      setError('Microphone access denied. Please allow microphone permissions.');
    }
  };

  const stopRecording = () => {
    mediaRecorder.current?.stop();
    mediaRecorder.current?.stream.getTracks().forEach(t => t.stop());
    setRecording(false);
    setStep('transcribing');
  };

  const handleTranscribe = async () => {
    const blob = new Blob(chunks.current, { type: 'audio/webm' });
    const formData = new FormData();
    formData.append('file', blob, 'recording.webm');
    try {
      const res = await fetch(`${AI}/api/v1/scribe/transcribe`, { method: 'POST', body: formData });
      const data = await res.json();
      setTranscript(data.text);
      setStep('generating');
      await handleGenerate(data.text);
    } catch (e: any) {
      setError('Transcription failed: ' + e.message);
      setStep('record');
    }
  };

  const handleGenerate = async (text: string) => {
    setLoading(true);
    try {
      const res = await fetch(`${AI}/api/v1/scribe/generate`, {
        method: 'POST', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({ transcript: text, encounter_type: 'visit' }),
      });
      const data = await res.json();
      setResult(data);
      setEdited({});
      setStep('done');
    } catch (e: any) { setError(e.message); }
    finally { setLoading(false); }
  };

  const handleManualTranscribe = async () => {
    if (!transcript) return;
    setStep('generating');
    await handleGenerate(transcript);
  };

  const update = (f: string, v: string) => setEdited((p:any) => ({...p,[f]:v}));
  const data = result ? { ...result, ...edited } : null;

  return (
    <div style={{maxWidth:900,margin:'0 auto',padding:'var(--spacing-4)'}}>
      <h1 style={{fontSize:'var(--font-size-2xl)',marginBottom:'var(--spacing-4)'}}>Live AI Scribe</h1>

      {!result && (
        <Card title="Encounter Recording">
          <p style={{color:'var(--color-neutral-500)',fontSize:14,marginBottom:16}}>
            Record the patient encounter. Whisper large-v3 will transcribe it, then the clinical AI generates a structured SOAP note.
          </p>
          <div style={{display:'flex',alignItems:'center',gap:16,flexWrap:'wrap'}}>
            {!recording ? (
              <Button onClick={startRecording} disabled={step==='transcribing'||step==='generating'}>
                {step==='transcribing'?'Transcribing...':step==='generating'?'Generating...':'Start Recording'}
              </Button>
            ) : (
              <Button variant="danger" onClick={stopRecording}>
                <span style={{display:'inline-block',width:8,height:8,borderRadius:'50%',background:'#fff',marginRight:8,animation:'pulse 1s infinite'}} /> Stop Recording
              </Button>
            )}
            <span style={{fontSize:14,color:'var(--color-neutral-500)'}}>
              {step==='transcribing' && 'Transcribing audio...'}
              {step==='generating' && 'AI generating SOAP note...'}
              {recording && <Badge variant="error">Recording</Badge>}
            </span>
          </div>
          {error && <div style={{marginTop:12,padding:10,background:'var(--color-error-light)',borderRadius:6,color:'var(--color-error)',fontSize:13}}>{error}</div>}

          <details style={{marginTop:16}}>
            <summary style={{cursor:'pointer',fontSize:13,color:'var(--color-neutral-500)'}}>Or paste transcript manually...</summary>
            <textarea value={transcript} onChange={e=>setTranscript(e.target.value)} rows={6} placeholder="Paste transcript here..."
              style={{width:'100%',padding:10,border:'1px solid var(--color-neutral-300)',borderRadius:6,fontSize:14,fontFamily:'var(--font-sans)',resize:'vertical',marginTop:8}} />
            <div style={{marginTop:8}}><Button onClick={handleManualTranscribe} disabled={!transcript||loading} size="sm">Generate SOAP Note</Button></div>
          </details>
        </Card>
      )}

      {data && (
        <div style={{marginTop:'var(--spacing-4)'}}>
          <Tabs tabs={[
            {key:'soap',label:'SOAP Note'},
            {key:'billing',label:`Billing (${data.billing_suggestions?.length||0})`},
            {key:'rx',label:`Rx (${data.prescription_suggestions?.length||0})`},
            {key:'labs',label:`Labs (${data.lab_suggestions?.length||0})`},
          ]} activeKey={tab} onChange={setTab} />

          <div style={{marginTop:'var(--spacing-4)'}}>
            {tab==='soap' && (
              <div style={{display:'flex',flexDirection:'column',gap:'var(--spacing-4)'}}>
                <EditableSection label="Subjective" value={data.subjective} onChange={v=>update('subjective',v)} />
                <EditableSection label="Objective" value={data.objective} onChange={v=>update('objective',v)} />
                <EditableSection label="Assessment" value={data.assessment} onChange={v=>update('assessment',v)} />
                <EditableSection label="Plan" value={data.plan} onChange={v=>update('plan',v)} />
                <div style={{padding:12,background:'var(--color-neutral-50)',borderRadius:8,fontSize:13}}>
                  <strong>Follow-up:</strong> {data.follow_up||'Not specified'}
                  {data.referral_needed && <span style={{marginLeft:12,color:'var(--color-warning)'}}>Referral: {data.referral_specialty} ({data.referral_urgency})</span>}
                </div>
                <details><summary style={{cursor:'pointer',fontSize:13,color:'var(--color-neutral-500)'}}>Transcript</summary>
                  <div style={{padding:12,background:'var(--color-neutral-50)',borderRadius:6,fontSize:13,whiteSpace:'pre-wrap',marginTop:8}}>{transcript}</div>
                </details>
              </div>
            )}

            {tab==='billing' && data.billing_suggestions?.map((b:any,i:number)=>(
              <div key={i} style={{display:'flex',justifyContent:'space-between',padding:8,borderBottom:'1px solid var(--color-neutral-100)',alignItems:'center'}}>
                <span><strong>{b.code}</strong> {b.description}</span>
                <strong style={{color:'var(--color-primary-700)'}}>${b.fee?.toFixed(2)}</strong>
              </div>
            ))}
            {tab==='rx' && data.prescription_suggestions?.map((r:any,i:number)=>(
              <div key={i} style={{padding:8,border:'1px solid var(--color-neutral-200)',borderRadius:6,marginBottom:8}}>
                <strong>{r.drug} {r.dose}</strong> — {r.route} {r.frequency} x {r.duration}
                <div style={{fontSize:12,color:'var(--color-neutral-500)',marginTop:2}}>{r.rationale}</div>
              </div>
            ))}
            {tab==='labs' && data.lab_suggestions?.map((l:any,i:number)=>(
              <div key={i} style={{display:'flex',justifyContent:'space-between',padding:8,borderBottom:'1px solid var(--color-neutral-100)'}}>
                <strong>{l.test}</strong>
                <Badge variant={l.urgency==='stat'?'error':l.urgency==='urgent'?'warning':'info'}>{l.urgency}</Badge>
              </div>
            ))}
          </div>

          <div style={{marginTop:'var(--spacing-4)',display:'flex',gap:8,justifyContent:'flex-end'}}>
            <Button variant="secondary" onClick={()=>{setResult(null);setStep('record');setTranscript('');}}>New Recording</Button>
          </div>
        </div>
      )}

      <style>{`@keyframes pulse {0%,100%{opacity:1}50%{opacity:0.3}}`}</style>
    </div>
  );
}

function EditableSection({label,value,onChange}:{label:string;value:string;onChange:(v:string)=>void}) {
  return (
    <div>
      <h4 style={{fontSize:14,fontWeight:600,marginBottom:4,color:'var(--color-primary-700)'}}>{label}</h4>
      <textarea value={value} onChange={e=>onChange(e.target.value)} rows={3}
        style={{width:'100%',padding:8,fontSize:13,border:'1px solid var(--color-neutral-300)',borderRadius:6,fontFamily:'var(--font-sans)',resize:'vertical'}} />
    </div>
  );
}

const el = document.getElementById('scribe-root');
if (el) createRoot(el).render(<LiveScribe />);
